function [nmbImg,imgLst] = fDutchShtLstAllV01(espcDir,nmbSht)% Function to get a list and number of images% for Dutch magspec analysis%% [nmbImg,imgLst] = fDutchShtLstAllV01(espcDir,nmbSht)%% espcDir: a cell of directories to look for images% nmbSht: number of shots from trex logfile% nmbImg: number of images that all exist% imgLst: image list (list of shot number)%% Kei Nakamura% Created on Tuesday, November 16th 2010.% Modified on  %% ver.2: %% mainimgExst1 = fDutchShtLstV01(espcDir{1},nmbSht,1);    % get a list for cam1imgExst2 = fDutchShtLstV01(espcDir{2},nmbSht,2);    % get a list for cam2imgExst3 = fDutchShtLstV01(espcDir{3},nmbSht,3);    % get a list for cam3imgExst = imgExst1.*imgExst2.*imgExst3;   % 1 if all existnmbImg = sum(imgExst);                  % total number of shot all existaaa = [1:nmbSht]';imgExst = imgExst.*aaa;imgLst = find(imgExst~=0);
